const syntheticBox = (
  id: string,
  status: "candidate" | "active" | "done" | "dismissed" | "blocked",
  evidenceCount: number,
  blocked: boolean,
) => ({
  blocked_by: [],
  blocks: [],
  box_id: id,
  capability: { id: `cap_${id}`, name: `Capability ${id.toUpperCase()}` },
  derived: true,
  ...(blocked ? { deviation: { kind: "superseded_sop" } } : {}),
  effect_class: "read_only" as const,
  evidence: Array.from({ length: evidenceCount }, (_, i) => ({
    document_id: `d9${id.slice(-1)}0${i}`,
    sensitivity: "internal" as const,
    title: `Synthetic Evidence ${i + 1}`,
    ...(blocked && i === 0 ? { superseded: true as const } : {}),
  })),
  honesty: { band: 3, groups: ["grp_synth"], sites: ["site_one"] },
  provenance: {
    initiative: { id: "init_x", name: "Initiative X" },
    strategy: { id: "strat_x", name: "Strategy X" },
    workflow: { id: "wf_x", name: "Workflow X" },
  },
  snapshot_version: "synthetic",
  sop_state: (blocked ? "blocked_superseded" : "current") as
    | "current"
    | "blocked_superseded",
  status,
  why: "Part of Workflow X under Initiative X, serving Strategy X.",
});

